+    #[test]
+    fn series_head_tail() {
+        let s = Series::from_values(
+            "vals",
+            vec![
+                IndexLabel::from("a"),
+                IndexLabel::from("b"),
+                IndexLabel::from("c"),
+                IndexLabel::from("d"),
+                IndexLabel::from("e"),
+            ],
+            vec![
+                Scalar::Int64(1),
+                Scalar::Int64(2),
+                Scalar::Int64(3),
+                Scalar::Int64(4),
+                Scalar::Int64(5),
+            ],
+        )
+        .unwrap();
+
+        let head = s.head(3).unwrap();
+        assert_eq!(
+            head.index().labels(),
+            &[
+                IndexLabel::from("a"),
+                IndexLabel::from("b"),
+                IndexLabel::from("c")
+            ]
+        );
+        assert_eq!(
+            head.values(),
+            &[Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)]
+        );
+
+        let tail = s.tail(2).unwrap();
+        assert_eq!(
+            tail.index().labels(),
+            &[IndexLabel::from("d"), IndexLabel::from("e")]
+        );
+        assert_eq!(tail.values(), &[Scalar::Int64(4), Scalar::Int64(5)]);
+    }
+
+    #[test]
+    fn series_head_tail_negative_n() {
+        let s = Series::from_values(
+            "vals",
+            vec![
+                0_i64.into(),
+                1_i64.into(),
+                2_i64.into(),
+                3_i64.into(),
+                4_i64.into(),
+            ],
+            vec![
+                Scalar::Int64(10),
+                Scalar::Int64(20),
+                Scalar::Int64(30),
+                Scalar::Int64(40),
+                Scalar::Int64(50),
+            ],
+        )
+        .unwrap();
+
+        let head = s.head(-2).unwrap();
+        assert_eq!(
+            head.values(),
+            &[Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(30)]
+        );
+
+        let tail = s.tail(-2).unwrap();
+        assert_eq!(
+            tail.values(),
+            &[Scalar::Int64(30), Scalar::Int64(40), Scalar::Int64(50)]
+        );
+    }
+
+    #[test]
+    fn series_head_tail_negative_n_saturates_to_empty() {
+        let s = Series::from_values(
+            "vals",
+            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
+            vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
+        )
+        .unwrap();
+
+        let head = s.head(-10).unwrap();
+        assert_eq!(head.len(), 0);
+        assert_eq!(head.values(), &[]);
+
+        let tail = s.tail(-10).unwrap();
+        assert_eq!(tail.len(), 0);
+        assert_eq!(tail.values(), &[]);
+    }
+
